template<typename StringType>
inline void replace_substring(StringType& s, const StringType& f,
                              const StringType& t)
{
    JSON_ASSERT(!f.empty());
    for (auto pos = s.find(f);                // find the first occurrence of f
            pos != StringType::npos;          // make sure f was found
            s.replace(pos, f.size(), t),      // replace with t, and
            pos = s.find(f, pos + t.size()))  // find the next occurrence of f
    {}
}

bool GradientProblem::Evaluate(const double* parameters,
                               double* cost,
                               double* gradient) const {
  if (gradient == nullptr) {
    return function_->Evaluate(parameters, cost, nullptr);
  }

  return (function_->Evaluate(parameters, cost, scratch_.get()) &&
          manifold_->RightMultiplyByPlusJacobian(
              parameters, 1, scratch_.get(), gradient));
}

coroutine_handle<> await_suspend(
    coroutine_handle<Promise> continuation) noexcept {
  if constexpr (detail::promiseHasAsyncFrame_v<Promise>) {
    barrier_.setContinuation(
        continuation, &continuation.promise().getAsyncFrame());
    return barrier_.arrive(continuation.promise().getAsyncFrame());
  } else {
    barrier_.setContinuation(continuation, nullptr);
    return barrier_.arrive();
  }
}

